defmodule DevopsAutomationWeb.CommandController do
  use DevopsAutomationWeb, :controller

  alias DevopsAutomation.CommandService

  @doc """
  POST /api/commands/execute
  Body: {"command": "disk_usage", "args": ["-h"]}
  """
  def execute(conn, params) do
    with {:ok, command_name} <- extract_command(params),
         {:ok, args} <- extract_args(params),
         {:ok, result} <- CommandService.execute(command_name, args) do
      conn
      |> put_status(:ok)
      |> json(%{status: "success", data: result})
    else
      {:error, :command_not_allowed} ->
        conn
        |> put_status(:bad_request)
        |> json(%{
          status: "error",
          message: "Command not allowed",
          allowed_commands: CommandService.allowed_commands()
        })

      {:error, {:args_not_allowed, detail}} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: "Invalid arguments", detail: detail})

      {:error, {:too_many_args, detail}} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: detail})

      {:error, :shell_metacharacters_not_allowed} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: "Arguments contain disallowed characters"})

      {:error, :null_bytes_not_allowed} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: "Arguments contain null bytes"})

      {:error, :args_must_be_strings} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: "All arguments must be strings"})

      {:error, {:invalid_service_name, detail}} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: detail})

      {:error, {:executable_not_found, path}} ->
        conn
        |> put_status(:internal_server_error)
        |> json(%{status: "error", message: "Executable not found: #{path}"})

      {:error, %{output: output, exit_code: exit_code}} ->
        conn
        |> put_status(:unprocessable_entity)
        |> json(%{status: "error", output: output, exit_code: exit_code})

      {:error, {:execution_error, message}} ->
        conn
        |> put_status(:internal_server_error)
        |> json(%{status: "error", message: "Execution error: #{message}"})

      {:error, reason} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: "Request error: #{inspect(reason)}"})
    end
  end

  @doc """
  GET /api/commands
  Returns the list of allowed commands and their options.
  """
  def index(conn, _params) do
    commands =
      CommandService.allowed_commands()
      |> Enum.map(fn name ->
        {:ok, spec} = CommandService.command_spec(name)
        %{
          name: name,
          allowed_args: Map.get(spec, :allowed_args, []),
          max_args: Map.get(spec, :max_args, 2)
        }
      end)

    conn
    |> put_status(:ok)
    |> json(%{status: "success", commands: commands})
  end

  defp extract_command(%{"command" => command}) when is_binary(command), do: {:ok, command}
  defp extract_command(_), do: {:error, :missing_command}

  defp extract_args(%{"args" => args}) when is_list(args), do: {:ok, args}
  defp extract_args(%{"args" => _}), do: {:error, :args_must_be_list}
  defp extract_args(_), do: {:ok, []}
end